#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int missing[K];
        for (int i = 0; i < K; i++) {
            scanf("%d", &missing[i]);
        }
        int nim_sum = 0;
        for (int i = 0; i < K; i++) {
            nim_sum ^= missing[i];
        }
        if (nim_sum == 0) {
            printf("Mom\n");
        } else {
            printf("Chef\n");
        }
    }
    return 0;
}

