import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] missing = new int[K];
            for (int i = 0; i < K; i++) {
                missing[i] = sc.nextInt();
            }
            int nim_sum = 0;
            for (int i = 0; i < K; i++) {
                nim_sum ^= missing[i];
            }
            if (nim_sum == 0) {
                System.out.println("Mom");
            } else {
                System.out.println("Chef");
            }
        }
    }
}

